// src/storage/preferences.ts
import { PREFERENCES_STORAGE_KEY, DEFAULT_PREFERENCES } from '../utils/constants';
import type { UserPreferences, ATSSearchPreferences } from '../types/preferences';

/**
 * Migrates legacy OR-separated search strings to arrays.
 */
const migrateAtsSearch = (atsSearch: any): ATSSearchPreferences => {
  if (!atsSearch) return DEFAULT_PREFERENCES.atsSearch!;

  const migrateField = (field: any): string[] => {
    if (Array.isArray(field)) return field;
    if (typeof field !== 'string') return [];

    // Split by " OR " (case-insensitive), remove quotes and trim
    return field
      .split(/ OR /i)
      .map(part => part.trim().replace(/^"(.*)"$/, '').replace(/^'(.*)'$/, ''))
      .filter(part => part.length > 0);
  };

  return {
    roles: migrateField(atsSearch.roles),
    keywords: migrateField(atsSearch.keywords),
    location: migrateField(atsSearch.location),
  };
};

/**
 * Obtiene las preferencias del usuario desde localStorage.
 */
export const getPreferences = (): UserPreferences => {
  try {
    const stored = localStorage.getItem(PREFERENCES_STORAGE_KEY);
    if (!stored) {
      return DEFAULT_PREFERENCES;
    }
    const parsed = JSON.parse(stored) as any;

    // Merge with defaults to be resilient to schema changes
    const enabledFields = parsed.enabledFields && parsed.enabledFields.length > 0
      ? parsed.enabledFields
      : DEFAULT_PREFERENCES.enabledFields;

    const columnOrder = parsed.columnOrder && parsed.columnOrder.length > 0
      ? parsed.columnOrder
      : DEFAULT_PREFERENCES.columnOrder;

    const customFields = parsed.customFields ?? DEFAULT_PREFERENCES.customFields;

    const defaultView = (parsed.defaultView && ['table', 'timeline', 'kanban', 'calendar'].includes(parsed.defaultView))
      ? parsed.defaultView
      : DEFAULT_PREFERENCES.defaultView;

    const dateFormat = (parsed.dateFormat && ['DD/MM/YYYY', 'MM/DD/YYYY', 'YYYY-MM-DD'].includes(parsed.dateFormat))
      ? parsed.dateFormat
      : DEFAULT_PREFERENCES.dateFormat;

    const customInterviewEvents = parsed.customInterviewEvents ?? DEFAULT_PREFERENCES.customInterviewEvents;

    // Migrate ATS search if it exists
    const atsSearch = migrateAtsSearch(parsed.atsSearch);

    return {
      ...DEFAULT_PREFERENCES,
      ...parsed,
      enabledFields,
      columnOrder,
      customFields,
      defaultView,
      dateFormat,
      customInterviewEvents,
      atsSearch,
    };
  } catch (error) {
    console.error('Error loading preferences from localStorage:', error);
    return DEFAULT_PREFERENCES;
  }
};

/**
 * Guarda las preferencias del usuario en localStorage.
 */
export const savePreferences = (preferences: UserPreferences): void => {
  try {
    localStorage.setItem(PREFERENCES_STORAGE_KEY, JSON.stringify(preferences));
  } catch (error) {
    console.error('Error saving preferences to localStorage:', error);
  }
};

import { create } from 'zustand';
import { setLoginStatus } from '../storage/auth';

interface User {
  id: number;
  email: string;
  name?: string;
  picture?: string;
}

interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  error: string | null;

  // Actions
  setUser: (user: User | null) => void;
  setAuthenticated: (status: boolean) => void;
  setError: (error: string | null) => void;
  logout: () => Promise<void>;
  checkAuth: () => Promise<void>;
}

export const useAuthStore = create<AuthState>()((set) => ({
  user: null,
  isAuthenticated: false,
  isLoading: false,
  error: null,

  setUser: (user) => set({ user, isAuthenticated: !!user }),
  setAuthenticated: (status) => set({ isAuthenticated: status }),
  setError: (error) => set({ error }),

  logout: async () => {
    try {
      await fetch('/api/auth/logout', { method: 'DELETE' });
      set({ user: null, isAuthenticated: false });
      setLoginStatus(false);
    } catch (err) {
      console.error('Logout failed', err);
    }
  },

  checkAuth: async () => {
    set({ isLoading: true });
    try {
      const res = await fetch('/api/auth/me');
      if (res.ok) {
        const data = await res.json();
        if (data.success) {
          set({ user: data.user, isAuthenticated: true });
          setLoginStatus(true);
        } else {
          set({ user: null, isAuthenticated: false });
          setLoginStatus(false);
        }
      } else {
        set({ user: null, isAuthenticated: false });
        setLoginStatus(false);
      }
    } catch (err) {
      set({ user: null, isAuthenticated: false });
      setLoginStatus(false);
    } finally {
      set({ isLoading: false });
    }
  },
}));

import type { JobApplication } from '../types/applications';
import { generateId } from './id';

/**
 * Exports an array of JobApplication to a CSV string.
 */
export const exportToCSV = (applications: JobApplication[]): string => {
  if (applications.length === 0) return '';

  const columns: (keyof JobApplication)[] = [
    'id', 'position', 'company', 'location', 'workType',
    'hybridDaysInOffice', 'salary', 'status', 'applicationDate',
    'interviewDate', 'notes', 'link', 'platform', 'contactName', 'followUpDate'
  ];

  const headers = [...columns, 'timeline', 'customFields'];

  const csvRows = [];
  csvRows.push(headers.join(','));

  for (const app of applications) {
    const values = headers.map(header => {
      const val = app[header as keyof JobApplication];
      let stringValue = '';

      if (val === undefined || val === null) {
        stringValue = '';
      } else if (typeof val === 'object') {
        stringValue = JSON.stringify(val);
      } else {
        stringValue = String(val);
      }

      // Escape double quotes and wrap in double quotes
      const escaped = stringValue.replace(/"/g, '""');
      return `"${escaped}"`;
    });
    csvRows.push(values.join(','));
  }

  return csvRows.join('\n');
};

/**
 * Parses a CSV string into an array of JobApplication.
 */
export const parseCSV = (csvText: string): JobApplication[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];

  const headers = lines[0].split(',').map(h => h.replace(/^"|"$/g, '').trim());
  const applications: JobApplication[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    if (!line.trim()) continue;

    const values: string[] = [];
    let current = '';
    let inQuotes = false;

    for (let j = 0; j < line.length; j++) {
      const char = line[j];
      if (char === '"') {
        if (inQuotes && line[j + 1] === '"') {
          current += '"';
          j++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === ',' && !inQuotes) {
        values.push(current);
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current);

    const app: any = {};
    headers.forEach((header, index) => {
      let value = values[index] || '';

      if (header === 'timeline' || header === 'customFields') {
        try {
          app[header] = value ? JSON.parse(value) : (header === 'timeline' ? [] : {});
        } catch {
          app[header] = header === 'timeline' ? [] : {};
        }
      } else if (header === 'hybridDaysInOffice') {
        app[header] = value ? parseInt(value, 10) : undefined;
      } else {
        app[header] = value;
      }
    });

    // Ensure it has an ID
    if (!app.id) {
      app.id = generateId();
    }

    // Validate required fields at least exist
    if (app.position && app.company) {
      applications.push(app as JobApplication);
    }
  }

  return applications;
};
